import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableTimes, setAvailableTimes] = useState([]);

  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  const [popup, setPopup] = useState({ show: false, message: "" });

  // ================= FETCH DOCTOR =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: { Authorization: `Token ${localStorage.getItem("token")}` },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableTimes(data.doctor.available_time_slots || []);
      });
  }, [doctor_id]);

  // ================= FETCH FEEDBACK =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: { Authorization: `Token ${localStorage.getItem("token")}` },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data));
  }, [doctor_id]);

  // ================= POPUP =================
  const showPopup = (msg) => {
    setPopup({ show: true, message: msg });
  };

  // ================= BOOK =================
  const handleBook = async () => {
    if (!date || !time) return showPopup("Please select date & time");

    const token = localStorage.getItem("token");

    const res = await fetch("http://127.0.0.1:8000/book-appointment/", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${token}`,
      },
      body: JSON.stringify({
        doctor_id,
        appointment_date: date,
        time_slot: time,
      }),
    });

    const data = await res.json();

    if (res.ok) {
      showPopup("Appointment booked successfully!");
      setTimeout(() => navigate("/myappointments"), 1500);
    } else {
      showPopup(data.error || "Booking failed");
    }
  };

  // ================= FEEDBACK =================
  const submitFeedback = () => {
    if (!rating || !comment) return showPopup("Please add rating & comment");

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");
        showPopup("Review submitted!");
      });
  };

  if (!doctor) return <h2 style={styles.loading}>Loading...</h2>;

  const avg =
    feedbacks.length > 0
      ? (feedbacks.reduce((a, b) => a + b.rating, 0) / feedbacks.length).toFixed(1)
      : 0;

  return (
    <div style={styles.page}>
      <Navbar />

      {/* ================= MODERN POPUP ================= */}
      {popup.show && (
        <div style={styles.overlay}>
          <div style={styles.popup}>
            <div style={styles.popupIcon}>✓</div>
            <h3 style={{ marginBottom: 10 }}>Notification</h3>
            <p>{popup.message}</p>
            <button onClick={() => setPopup({ show: false })} style={styles.popupBtn}>
              OK
            </button>
          </div>
        </div>
      )}

      {/* ================= MAIN CARD ================= */}
      <div style={styles.container}>
        <div style={styles.card}>
          <div style={styles.left}>
            <img src={doctor.image} style={styles.image} />
            <h3>{doctor.name}</h3>
            <p style={{ color: "#666" }}>{doctor.field}</p>
          </div>

          <div style={styles.right}>

            {/* BOOKING */}
            <div style={styles.section}>
              <h3>Book Appointment</h3>

              <input type="date" style={styles.input} onChange={(e) => setDate(e.target.value)} />

              <select style={styles.input} onChange={(e) => setTime(e.target.value)}>
                <option>Select Time</option>
                {availableTimes.map((t, i) => (
                  <option key={i}>{t}</option>
                ))}
              </select>

              <button style={styles.primaryBtn} onClick={handleBook}>
                Confirm Booking
              </button>
            </div>

            {/* ================= FEEDBACK PROFESSIONAL ================= */}
            <div style={styles.section}>
              <div style={styles.feedbackHeader}>
                <h3>Patient Reviews</h3>
                <div style={styles.ratingBadge}>{avg} ⭐</div>
              </div>

              {/* FORM */}
              <div style={styles.feedbackBox}>
                <select style={styles.input} onChange={(e) => setRating(e.target.value)}>
                  <option value="">Select Rating</option>
                  <option value="5">⭐⭐⭐⭐⭐ Excellent</option>
                  <option value="4">⭐⭐⭐⭐ Good</option>
                  <option value="3">⭐⭐⭐ Average</option>
                  <option value="2">⭐⭐ Poor</option>
                  <option value="1">⭐ Bad</option>
                </select>

                <textarea
                  placeholder="Write your experience..."
                  style={styles.textarea}
                  value={comment}
                  onChange={(e) => setComment(e.target.value)}
                />

                <button style={styles.secondaryBtn} onClick={submitFeedback}>
                  Submit Review
                </button>
              </div>

              {/* REVIEWS LIST */}
              <div style={styles.reviewList}>
                {feedbacks.map((fb) => (
                  <div key={fb.id} style={styles.reviewCard}>
                    <div style={styles.reviewTop}>
                      <b>{fb.user_name}</b>
                      <span style={styles.star}>{fb.rating} ⭐</span>
                    </div>
                    <p style={{ marginTop: 5, color: "#555" }}>{fb.comment}</p>
                  </div>
                ))}
              </div>
            </div>

          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

/* ================= STYLES ================= */
const styles = {
  page: { background: "#f4f6f9", minHeight: "100vh" },

  container: {
    display: "flex",
    justifyContent: "center",
    padding: 30,
  },

  card: {
    display: "flex",
    width: "950px",
    background: "#fff",
    borderRadius: 15,
    boxShadow: "0 10px 30px rgba(0,0,0,0.1)",
    overflow: "hidden",
  },

  left: {
    width: "30%",
    padding: 20,
    textAlign: "center",
    borderRight: "1px solid #eee",
  },

  image: {
    width: 120,
    height: 120,
    borderRadius: "50%",
    objectFit: "cover",
    marginBottom: 10,
  },

  right: {
    width: "70%",
    padding: 25,
  },

  section: {
    marginBottom: 25,
  },

  input: {
    width: "100%",
    padding: 10,
    margin: "8px 0",
    border: "1px solid #ddd",
    borderRadius: 8,
  },

  textarea: {
    width: "100%",
    height: 80,
    padding: 10,
    borderRadius: 8,
    border: "1px solid #ddd",
  },

  primaryBtn: {
    width: "100%",
